{
  "files": [
    {"path": "README.md", "content": "# Project Management API

This is a simple project management API built using Node.js with Express for handling HTTP requests.
It includes endpoints for managing projects, tasks, and comments."},
    {"path": "package.json", "content": "{ "name": "project-management-api", "version": "1.0.0", "main": "src/app.js", "scripts": { "start": "node src/server.js" }, "dependencies": { "express": "^4.17.1", "crypto": "^1.0.0" } }"},
    {"path": "src/app.js", "content": "const express = require('express');
const app = express();
const crypto = require('crypto');
const { randomUUID } = require('crypto');
const projectsRouter = require('./modules/projects/routes');
const tasksRouter = require('./modules/tasks/routes');
const membersRouter = require('./modules/members/routes');
const commentsRouter = require('./modules/comments/routes');
app.use(express.json());
app.get('/health', (req, res) => { res.json({ ok: true }); });
app.use('/projects', projectsRouter);
app.use('/projects/:projectId/members', membersRouter);
app.use('/projects/:projectId/tasks', tasksRouter);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRouter);
module.exports = app;"},
    {"path": "src/server.js", "content": "const app = require('./app');
const port = process.env.PORT || 3000;
app.listen(port, () => { console.log(`Server running on port ${port}`); });"},
    {"path": "src/modules/projects/routes.js", "content": "const express = require('express');
const router = express.Router();
const service = require('./service');
router.post('/', (req, res) => { service.createProject(req, res); });
module.exports = router;"},
    {"path": "src/modules/projects/service.js", "content": "const createProject = (req, res) => { const projectId = randomUUID(); res.json({ projectId }); };
module.exports = { createProject };"},
    {"path": "src/modules/tasks/routes.js", "content": "const express = require('express');
const router = express.Router({ mergeParams: true });
const service = require('./service');
router.post('/', (req, res) => { service.createTask(req, res); });
module.exports = router;"},
    {"path": "src/modules/tasks/service.js", "content": "const createTask = (req, res) => { const taskId = randomUUID(); res.json({ task: { id: taskId, title: req.body.title } }); };
module.exports = { createTask };"},
    {"path": "src/modules/members/routes.js", "content": "const express = require('express');
const router = express.Router({ mergeParams: true });
const service = require('./service');
router.post('/', (req, res) => { service.addMember(req, res); });
module.exports = router;"},
    {"path": "src/modules/members/service.js", "content": "const addMember = (req, res) => { const memberId = randomUUID(); res.json({ member: { userId: req.body.userId, role: req.body.role } }); };
module.exports = { addMember };"},
    {"path": "src/modules/comments/routes.js", "content": "const express = require('express');
const router = express.Router({ mergeParams: true });
const service = require('./service');
router.post('/', (req, res) => { service.addComment(req, res); });
module.exports = router;"},
    {"path": "src/modules/comments/service.js", "content": "const addComment = (req, res) => { const commentId = randomUUID(); res.json({ comment: { message: req.body.message } }); };
module.exports = { addComment };"},
    {"path": "src/lib/errors.js", "content": "class CustomError extends Error {
  constructor(code, message) { super(message); this.code = code; }
}
module.exports = { CustomError };"},
    {"path": "src/lib/id.js", "content": "const { randomUUID } = require('crypto');
module.exports = { randomUUID };"}
  ],
  "mode": "full"
}
